$headers = @{ "User-Agent" = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36" }

foreach ($entry in $screens.GetEnumerator()) {
    $file = $entry.Key
    $url = $entry.Value
    try {
        Write-Host "Downloading $file ..."
        $response = Invoke-WebRequest -Uri $url -Headers $headers -TimeoutSec 30 -UseBasicParsing
        [System.IO.File]::WriteAllBytes((Resolve-Path ".").Path + "\" + $file, $response.Content)
        Write-Host "OK  $file ($($response.Content.Length) bytes)"
    } catch {
        Write-Host "ERR $file : $_"
    }
    Start-Sleep -Milliseconds 500
}
Write-Host "Done."
